import{_ as r,o as i,c as l,ai as n}from"./chunks/framework.ampVZV4B.js";const b=JSON.parse('{"title":"前端工程化","description":"","frontmatter":{},"headers":[],"relativePath":"tech-system/frontend/engineering.md","filePath":"tech-system/frontend/engineering.md"}'),e={name:"tech-system/frontend/engineering.md"};function t(o,a,s,g,h,d){return i(),l("div",null,[...a[0]||(a[0]=[n('<h1 id="前端工程化" tabindex="-1">前端工程化 <a class="header-anchor" href="#前端工程化" aria-label="Permalink to “前端工程化”">​</a></h1><p>前端工程化是指将前端开发过程标准化、规范化、自动化的一系列技术和实践。通过工程化手段提高代码质量、开发效率和可维护性。</p><h2 id="模块打包" tabindex="-1">模块打包 <a class="header-anchor" href="#模块打包" aria-label="Permalink to “模块打包”">​</a></h2><h3 id="webpack" tabindex="-1">Webpack <a class="header-anchor" href="#webpack" aria-label="Permalink to “Webpack”">​</a></h3><ul><li><strong>核心概念</strong>: Entry、Output、Loaders、Plugins</li><li><strong>资源管理</strong>: 引入库、处理样式、处理资源</li><li><strong>模块代码分割</strong>: Dynamic Imports、Route Splitting、Vendor Separation</li><li><strong>性能优化</strong>: Tree Shaking、Minification、Lazy Loading</li><li><strong>开发体验</strong>: Hot Module Replacement、DevServer、Source Maps</li></ul><h3 id="vite" tabindex="-1">Vite <a class="header-anchor" href="#vite" aria-label="Permalink to “Vite”">​</a></h3><ul><li><strong>Next Generation</strong>: ES Module、快速开发、极速冷启动</li><li><strong>特点</strong>: 按需编译、原生 ESM、开发体验优秀</li><li><strong>插件系统</strong>: 框架集成、NPM 依赖预捆绑</li><li><strong>构建优化</strong>: Rollup 打包、动态导入、CSS 分割</li></ul><h3 id="其他工具" tabindex="-1">其他工具 <a class="header-anchor" href="#其他工具" aria-label="Permalink to “其他工具”">​</a></h3><ul><li><strong>Parcel</strong>: 零配置打包、快速开发、自动优化</li><li><strong>Rollup</strong>: 库打包、三方依赖打包、虚拟插件</li><li><strong>esbuild</strong>: 极速编译器、Go 实现、构建加速</li></ul><h2 id="转译编译" tabindex="-1">转译编译 <a class="header-anchor" href="#转译编译" aria-label="Permalink to “转译编译”">​</a></h2><h3 id="typescript" tabindex="-1">TypeScript <a class="header-anchor" href="#typescript" aria-label="Permalink to “TypeScript”">​</a></h3><ul><li><strong>类型系统</strong>: 基础类型、泛型、类型推断</li><li><strong>高级特性</strong>: 装饰器、元数据、Enum</li><li><strong>编译配置</strong>: tsconfig.json、编译选项、输出配置</li><li><strong>类型定义</strong>: .d.ts、类型声明、DefinitelyTyped</li></ul><h3 id="babel" tabindex="-1">Babel <a class="header-anchor" href="#babel" aria-label="Permalink to “Babel”">​</a></h3><ul><li><strong>转译</strong>: ECMAScript 最新语法转换、兼容旧浏览器</li><li><strong>插件系统</strong>: 功能扩展、自定义转译、AST 操作</li><li><strong>预设</strong>: env、react、flow、集合方案</li><li><strong>性能</strong>: 编译缓存、构建加速</li></ul><h3 id="预处理器" tabindex="-1">预处理器 <a class="header-anchor" href="#预处理器" aria-label="Permalink to “预处理器”">​</a></h3><ul><li><strong>SCSS/SASS</strong>: 变量、Mixin、Nesting、导入</li><li><strong>Less</strong>: 动态样式、函数、作用域</li><li><strong>Stylus</strong>: 简洁语法、元编程</li></ul><h2 id="代码质量" tabindex="-1">代码质量 <a class="header-anchor" href="#代码质量" aria-label="Permalink to “代码质量”">​</a></h2><h3 id="linting" tabindex="-1">Linting <a class="header-anchor" href="#linting" aria-label="Permalink to “Linting”">​</a></h3><ul><li><strong>ESLint</strong>: 代码规范、错误检测、自动修复</li><li><strong>Stylelint</strong>: 样式规范、CSS 检测</li><li><strong>规则配置</strong>: 共享配置、插件、自定义规则</li></ul><h3 id="格式化" tabindex="-1">格式化 <a class="header-anchor" href="#格式化" aria-label="Permalink to “格式化”">​</a></h3><ul><li><strong>Prettier</strong>: 代码格式化、一致性风格、强制统一</li><li><strong>EditorConfig</strong>: 跨编辑器配置、缩进规范</li><li><strong>集成工具</strong>: Pre-commit hooks、IDE 集成</li></ul><h3 id="测试框架" tabindex="-1">测试框架 <a class="header-anchor" href="#测试框架" aria-label="Permalink to “测试框架”">​</a></h3><ul><li><strong>单元测试</strong>: Jest、Vitest、Mocha</li><li><strong>端到端测试</strong>: Cypress、Playwright、WebDriver</li><li><strong>集成测试</strong>: Testing Library、Enzyme、Astro</li><li><strong>覆盖率</strong>: Coverage 统计、阈值控制</li></ul><h2 id="包管理" tabindex="-1">包管理 <a class="header-anchor" href="#包管理" aria-label="Permalink to “包管理”">​</a></h2><h3 id="npm-yarn-pnpm" tabindex="-1">npm/yarn/pnpm <a class="header-anchor" href="#npm-yarn-pnpm" aria-label="Permalink to “npm/yarn/pnpm”">​</a></h3><ul><li><strong>依赖管理</strong>: 版本控制、锁定文件、依赖解析</li><li><strong>性能</strong>: 并行下载、缓存、硬链接</li><li><strong>工作空间</strong>: Monorepo management、包管理</li><li><strong>脚本运行</strong>: npm scripts、生命周期、自定义命令</li></ul><h3 id="版本管理" tabindex="-1">版本管理 <a class="header-anchor" href="#版本管理" aria-label="Permalink to “版本管理”">​</a></h3><ul><li><strong>语义化版本</strong>: MAJOR、MINOR、PATCH</li><li><strong>版本范围</strong>: ^、~、*、精确版本</li><li><strong>发布流程</strong>: Changelog、Tag、NPM 发布</li></ul><h2 id="构建流程" tabindex="-1">构建流程 <a class="header-anchor" href="#构建流程" aria-label="Permalink to “构建流程”">​</a></h2><h3 id="ci-cd-集成" tabindex="-1">CI/CD 集成 <a class="header-anchor" href="#ci-cd-集成" aria-label="Permalink to “CI/CD 集成”">​</a></h3><ul><li><strong>GitHub Actions</strong>: 工作流、自动化测试、部署</li><li><strong>GitLab CI</strong>: Pipeline、Job、Stage</li><li><strong>Jenkins</strong>: 构建、测试、部署</li><li><strong>自动化</strong>: 代码检查、单元测试、集成部署</li></ul><h3 id="构建优化" tabindex="-1">构建优化 <a class="header-anchor" href="#构建优化" aria-label="Permalink to “构建优化”">​</a></h3><ul><li><strong>缓存</strong>: 构建缓存、依赖缓存、构建加速</li><li><strong>并行构建</strong>: 多进程、分布式构建</li><li><strong>增量构建</strong>: 增量编译、Diff 检测</li></ul><h2 id="开发工具" tabindex="-1">开发工具 <a class="header-anchor" href="#开发工具" aria-label="Permalink to “开发工具”">​</a></h2><h3 id="ide-编辑器" tabindex="-1">IDE/编辑器 <a class="header-anchor" href="#ide-编辑器" aria-label="Permalink to “IDE/编辑器”">​</a></h3><ul><li><strong>VS Code</strong>: 插件生态、扩展能力、集成开发</li><li><strong>WebStorm</strong>: 智能提示、集成工具、专业工具</li><li><strong>Vim/Neovim</strong>: 轻量级、高效编辑、可配置</li></ul><h3 id="调试工具" tabindex="-1">调试工具 <a class="header-anchor" href="#调试工具" aria-label="Permalink to “调试工具”">​</a></h3><ul><li><strong>DevTools</strong>: Chrome DevTools、性能分析、调试技巧</li><li><strong>Source Maps</strong>: 源代码映射、调试原始代码</li><li><strong>Debug 协议</strong>: CDP、远程调试、自定义工具</li></ul><h2 id="性能优化" tabindex="-1">性能优化 <a class="header-anchor" href="#性能优化" aria-label="Permalink to “性能优化”">​</a></h2><h3 id="代码分割" tabindex="-1">代码分割 <a class="header-anchor" href="#代码分割" aria-label="Permalink to “代码分割”">​</a></h3><ul><li><strong>路由分割</strong>: 按路由加载、减少初始包体积</li><li><strong>动态导入</strong>: import() 语法、条件加载</li><li><strong>vendor 分割</strong>: 第三方库隔离、缓存优化</li></ul><h3 id="代码压缩" tabindex="-1">代码压缩 <a class="header-anchor" href="#代码压缩" aria-label="Permalink to “代码压缩”">​</a></h3><ul><li><strong>Minification</strong>: 变量重命名、空白删除、死代码消除</li><li><strong>Tree Shaking</strong>: 无用代码删除、ES Module 前提</li><li><strong>CSS 优化</strong>: PurgeCSS、未使用样式删除</li></ul><h3 id="资源优化" tabindex="-1">资源优化 <a class="header-anchor" href="#资源优化" aria-label="Permalink to “资源优化”">​</a></h3><ul><li><strong>图片优化</strong>: 压缩、格式转换、响应式图片</li><li><strong>字体优化</strong>: Web Font、加载优化、 回退方案</li><li><strong>CDN</strong>: 内容分发、缓存策略</li></ul><h2 id="文档与认知" tabindex="-1">文档与认知 <a class="header-anchor" href="#文档与认知" aria-label="Permalink to “文档与认知”">​</a></h2><h3 id="代码文档" tabindex="-1">代码文档 <a class="header-anchor" href="#代码文档" aria-label="Permalink to “代码文档”">​</a></h3><ul><li><strong>注释规范</strong>: JSDoc、类型提示、参数说明</li><li><strong>README</strong>: 项目说明、安装步骤、使用示例</li><li><strong>API 文档</strong>: OpenAPI、Swagger、自动生成</li></ul><h3 id="知识共享" tabindex="-1">知识共享 <a class="header-anchor" href="#知识共享" aria-label="Permalink to “知识共享”">​</a></h3><ul><li><strong>最佳实践</strong>: 代码示例、问题记录、解决方案</li><li><strong>团队规范</strong>: 编码规范、架构规范、提交规范</li><li><strong>学习资源</strong>: 文档链接、视频教程、参考资料</li></ul><h2 id="工程化实践" tabindex="-1">工程化实践 <a class="header-anchor" href="#工程化实践" aria-label="Permalink to “工程化实践”">​</a></h2><h3 id="脚手架工具" tabindex="-1">脚手架工具 <a class="header-anchor" href="#脚手架工具" aria-label="Permalink to “脚手架工具”">​</a></h3><ul><li><strong>Create React App</strong>: 零配置、官方方案</li><li><strong>Vue CLI</strong>: 项目创建、配置管理</li><li><strong>Vite + 模板</strong>: 快速启动、现代工具链</li><li><strong>定制脚手架</strong>: 团队标准化、自动化工程</li></ul><h3 id="组件库" tabindex="-1">组件库 <a class="header-anchor" href="#组件库" aria-label="Permalink to “组件库”">​</a></h3><ul><li><strong>组件开发</strong>: 独立开发、文档生成、版本管理</li><li><strong>设计系统</strong>: 设计规范、组件标准、品牌一致</li><li><strong>打包发布</strong>: 多格式输出、TypeScript 支持、文档部署</li></ul><h3 id="监控与分析" tabindex="-1">监控与分析 <a class="header-anchor" href="#监控与分析" aria-label="Permalink to “监控与分析”">​</a></h3><ul><li><strong>性能监控</strong>: 首屏加载、FCP、LCP、性能指标</li><li><strong>错误追踪</strong>: 错误捕获、堆栈追踪、用户反馈</li><li><strong>用户分析</strong>: PV、UV、用户行为、转化漏斗</li></ul>',57)])])}const u=r(e,[["render",t]]);export{b as __pageData,u as default};
